# ── Fix: patch feedparser to use requests with 15s timeout (prevents RSS hangs) ──
import feedparser as _fp
import requests as _rq

_orig_fp_parse = _fp.parse

def _safe_fp_parse(url_or_data, *args, **kwargs):
    if isinstance(url_or_data, str) and url_or_data.startswith(('http://', 'https://')):
        try:
            _r = _rq.get(url_or_data, timeout=15,
                         headers={'User-Agent': 'Mozilla/5.0 (FeedFetcher/1.0)'},
                         allow_redirects=True)
            if _r.ok:
                return _orig_fp_parse(_r.content, *args, **kwargs)
        except Exception:
            pass
        return _fp.FeedParserDict()
    return _orig_fp_parse(url_or_data, *args, **kwargs)

_fp.parse = _safe_fp_parse
print("feedparser patched — all RSS fetches now use 15s timeout")


