import sys; sys.path.insert(0,'research_platform')

TICKER='RELIANCE'; SECTOR='petroleum'
HYPOTHESIS='RELIANCE undervalued — GRM recovery not priced in'
VARIANT='Consensus uses $6/bbl GRM; we model $9/bbl recovery'

from ai_engine.session_manager import new_session
ses = new_session(TICKER, hypothesis=HYPOTHESIS, variant_view=VARIANT)
ses.log_catalyst('Q1 FY27 results', expected_date='2026-07-15', catalyst_type='earnings')
print(f'Session:    {ses.session_id}')
print(f'Hypothesis: {ses.get_thesis()}')
print(f'Variant:    {ses.get_variant_view()}')

from ai_engine.dcf_bridge import build_full_assumptions
from ai_engine.assumption_engine import AssumptionEngine, compare_to_consensus
base = build_full_assumptions(TICKER, sector=SECTOR)
engine = AssumptionEngine(ses)
engine.initialize(base)
print(f'Assumptions: {len([k for k in base if not k.startswith("_")])} loaded')

from sqlalchemy import select, desc
from database.connection import get_session as dbs
from database.models import Event
from ai_engine.signal_detector import scan_events_for_signals, deduplicate_signals
from ai_engine.factor_engine import signals_to_factors
from datetime import date
with dbs() as db:
    rows = db.scalars(select(Event).order_by(desc(Event.created_at)).limit(100)).all()
    events = [{'title':r.title,'source':r.entity_type or 'news'} for r in rows]
signals = deduplicate_signals(scan_events_for_signals(events,ticker=TICKER,sector=SECTOR))
print(f'Signals: {len(signals)}')
for s in signals[:3]: print(f'  [{s.severity}] {s.signal_name}')

deltas  = signals_to_factors(signals, ses.get_assumptions())
updated = engine.process_deltas(deltas, event_date=date.today())

consensus = {'revenue_growth':6.0,'ebitda_margin':16.0,'wacc':12.5,'grm_usd_bbl':6.0}
divs = [d for d in compare_to_consensus(ses,consensus) if d['divergent']]
if divs: print('Divergent:', [(d["metric"], f"{d['difference']:+.2f}") for d in divs])

from ai_engine.scenario_engine import run_scenarios
run_scenarios(ses, updated, shares_outstanding=6760, base_revenue=9000000)
sc = ses.get_scenarios()
for label in ('bull','base','bear'):
    s2=sc['scenarios'][label]; up=s2.get('upside_pct')
    print(f'{label.upper()}: Rs{s2["price_per_share"]} ({f"{up:+.1f}%" if up else "N/A"}) [{s2["rating"].upper()}]')
rdcf = sc.get('reverse_dcf') or {}
print(f'Reverse DCF: {rdcf.get("implied_growth_rate","N/A")}% implied growth')

from ai_engine.audit_export import export_to_html, export_to_excel
print(f'Exported: {export_to_html(ses).name}  |  {export_to_excel(ses).name}')


